/**
 * Returns a list of short ID's
 *
 * @param numIDs number of short ID's to generate
 * @param numSkip a kind of starting index for short ID's
 * @returns a list of short ID's or empty array if numIDs is not an integer or less than one or numSkip is not an integer or less than 0
 */
declare function generateIDs(numIDs: number, numSkip: number): string[];

/**
 * Returns a in-memory representation of the element in working directory specified by element path
 *
 * @param workingDirectoryPath relative or absolute path to working directory containing yaml-datastore serialized content
 * @param elementPath object path (dot separated, with support for bracketed indexing for list elements or key-value pairs in objects) from working directory to element to be read into memory (e.g., top-element.sub-element.property[3])
 * @param depth integer from -1 to depth of element indicating how deep into element's hierachy to read into memory (-1 = read full depth. Defaults to -1), will not throw error if depth exceeds actual maximum depth of element
 * @returns a YdsResult containing the status and content of the load function
 */
declare function load(workingDirectoryPath: string, elementPath: string, depth?: number): YdsResult;

/**
 * Dumps in-memory representation of contents to on-disk representation
 *
 * @param element object or list to store on-disk
 * @param workingDirectoryPath relative or absolute path to an empty working directory to store element in
 * @param elementName name of element to store
 * @returns a YdsResult containing the status of the call to store function
 */
declare function store(element: object, workingDirectoryPath: string, elementName: string): YdsResult;

/**
 *
 * @param workingDirectoryPath relative or absolute path to working directory containing yaml-datastore serialized content
 * @param elementPath element path to element to be deleted
 * @param depth depth of element to be returned in YdsResult object
 * @returns a YdsResult containing the status of the call to deleteElement function
 */
declare function deleteElement(workingDirectoryPath: string, elementPath: string, depth?: number): YdsResult;

/**
 *
 * @param workingDirectoryPath relative or absolute path to working directory containing yaml-datastore serialized content
 * @param elementPath element path to element to be cleared
 * @param depth depth of element to be returned in YdsResult object
 * @returns a YdsResult containing the status of the call to clear function
 */
declare function clear(workingDirectoryPath: string, elementPath: string, depth?: number): YdsResult;

/**
 * Represents results of a yaml-datastore operation
 */
declare class YdsResult {
    private _success;
    private _element;
    private _message;
    /**
     * Default constructor for YdsResult
     *
     * @param success success status of a yaml-datastore operation
     * @param element element read into memory or stored on-disk per yaml-datastore operation
     * @param message message describing success status of a yaml-datastore operation
     * @returns new YdsResult object
     */
    constructor(success: boolean, element: any, message: string);
    /** @returns success status of a yaml-datastore operation. */
    get success(): boolean;
    /** @returns element read into memory or stored on-disk per yaml-datastore operation. */
    get element(): any;
    /** @returns message describing success status of a yaml-datastore operation. */
    get message(): string;
}

export { YdsResult, clear, deleteElement, generateIDs, load, store };
